   102→type ParsedTags map[string][]string
   103→
   104→func (p ParsedTags) Map(customMappings ParsedTags) ParsedTags {
   105→	if customMappings == nil {
   106→		return p
   107→	}
   108→	for tagName, alternatives := range customMappings {
   109→		for _, altName := range alternatives {
   110→			if altValue, ok := p[altName]; ok {
   111→				p[tagName] = append(p[tagName], altValue...)
   112→				delete(p, altName)
   113→			}
   114→		}
   115→	}
   116→	return p
   117→}
