   203→func (t Tags) Lyrics() string {
   204→	lyricList := model.LyricList{}
   205→	basicLyrics := t.getAllTagValues("lyrics", "unsynced_lyrics", "unsynced lyrics", "unsyncedlyrics")
   206→
   207→	for _, value := range basicLyrics {
   208→		lyrics, err := model.ToLyrics("xxx", value)
   209→		if err != nil {
   210→			log.Warn("Unexpected failure occurred when parsing lyrics", "file", t.filePath, "error", err)
   211→			continue
   212→		}
   213→
   214→		lyricList = append(lyricList, *lyrics)
   215→	}
   216→
   217→	for tag, value := range t.Tags {
   218→		if strings.HasPrefix(tag, "lyrics-") {
   219→			language := strings.TrimSpace(strings.TrimPrefix(tag, "lyrics-"))
   220→
   221→			if language == "" {
   222→				language = "xxx"
   223→			}
   224→
   225→			for _, text := range value {
   226→				lyrics, err := model.ToLyrics(language, text)
   227→				if err != nil {
   228→					log.Warn("Unexpected failure occurred when parsing lyrics", "file", t.filePath, "error", err)
   229→					continue
   230→				}
   231→
   232→				lyricList = append(lyricList, *lyrics)
   233→			}
   234→		}
   235→	}
   236→
   237→	res, err := json.Marshal(lyricList)
   238→	if err != nil {
