   245→func (t Tags) getGainValue(rgTagName, r128TagName string) float64 {
   246→	// Check for ReplayGain first
   247→	// ReplayGain is in the form [-]a.bb dB and normalized to -18dB
   248→	var tag = t.getFirstTagValue(rgTagName)
   249→	if tag != "" {
   250→		tag = strings.TrimSpace(strings.Replace(tag, "dB", "", 1))
   251→		var value, err = strconv.ParseFloat(tag, 64)
   252→		if err != nil || value == math.Inf(-1) || value == math.Inf(1) {
   253→			return 0
   254→		}
   255→		return value
   256→	}
   257→
   258→	// If ReplayGain is not found, check for R128 gain
   259→	// R128 gain is a Q7.8 fixed point number normalized to -23dB
   260→	tag = t.getFirstTagValue(r128TagName)
   261→	if tag != "" {
   262→		var iValue, err = strconv.Atoi(tag)
   263→		if err != nil {
   264→			return 0
   265→		}
   266→		// Convert Q7.8 to float
   267→		var value = float64(iValue) / 256.0
   268→		// Adding 5 dB to normalize with ReplayGain level
   269→		return value + 5
   270→	}
   271→
   272→	return 0
   273→}
