package scanner

import (
	"context"
	"io"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/google/uuid"
	"github.com/navidrome/navidrome/core"
	"github.com/navidrome/navidrome/core/artwork"
	"github.com/navidrome/navidrome/log"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/tests"
)

// IntegrationMediaFileRepo extends the mock to support scanner-specific methods
type IntegrationMediaFileRepo struct {
	*tests.MockMediaFileRepo
}

func (m *IntegrationMediaFileRepo) FindPathsRecursively(basePath string) ([]string, error) {
	if m.err {
		return nil, nil
	}
	var paths []string
	for _, mf := range m.data {
		if strings.HasPrefix(mf.Path, basePath) {
			paths = append(paths, mf.Path)
		}
	}
	return paths, nil
}

func (m *IntegrationMediaFileRepo) FindAllByPath(path string) (model.MediaFiles, error) {
	if m.err {
		return nil, nil
	}
	var result model.MediaFiles
	for _, mf := range m.data {
		dir := filepath.Dir(mf.Path)
		if filepath.Clean(dir) == filepath.Clean(path) {
			result = append(result, *mf)
		}
	}
	return result, nil
}

func (m *IntegrationMediaFileRepo) FindByPath(path string) (*model.MediaFile, error) {
	if m.err {
		return nil, nil
	}
	for _, mf := range m.data {
		if mf.Path == path {
			return mf, nil
		}
	}
	return nil, model.ErrNotFound
}

func (m *IntegrationMediaFileRepo) FindByPaths(paths []string) (model.MediaFiles, error) {
	if m.err {
		return nil, nil
	}
	var result model.MediaFiles
	pathMap := make(map[string]bool)
	for _, p := range paths {
		pathMap[p] = true
	}
	for _, mf := range m.data {
		if pathMap[mf.Path] {
			result = append(result, *mf)
		}
	}
	return result, nil
}

func (m *IntegrationMediaFileRepo) DeleteByPath(path string) (int64, error) {
	if m.err {
		return 0, nil
	}
	var count int64
	var toDelete []string
	for id, mf := range m.data {
		dir := filepath.Dir(mf.Path)
		if filepath.Clean(dir) == filepath.Clean(path) {
			toDelete = append(toDelete, id)
			count++
		}
	}
	for _, id := range toDelete {
		delete(m.data, id)
	}
	return count, nil
}

// IntegrationAlbumRepo extends the mock to support scanner-specific methods
type IntegrationAlbumRepo struct {
	*tests.MockAlbumRepo
}

func (m *IntegrationAlbumRepo) GetAll(qo ...model.QueryOptions) (model.Albums, error) {
	if m.err {
		return nil, nil
	}
	var albums model.Albums
	for _, album := range m.data {
		albums = append(albums, *album)
	}
	return albums, nil
}

// IntegrationArtistRepo extends the mock to support scanner-specific methods
type IntegrationArtistRepo struct {
	*tests.MockArtistRepo
}

func (m *IntegrationArtistRepo) GetAll(qo ...model.QueryOptions) (model.Artists, error) {
	if m.err {
		return nil, nil
	}
	var artists model.Artists
	for _, artist := range m.data {
		artists = append(artists, *artist)
	}
	return artists, nil
}

// IntegrationGenreRepo extends the mock to support scanner-specific methods
type IntegrationGenreRepo struct {
	*tests.MockedGenreRepo
	data map[string]*model.Genre
}

func (m *IntegrationGenreRepo) GetAll() (model.Genres, error) {
	var genres model.Genres
	for _, g := range m.data {
		genres = append(genres, *g)
	}
	return genres, nil
}

func (m *IntegrationGenreRepo) Put(g *model.Genre) error {
	if g.ID == "" {
		g.ID = uuid.NewString()
	}
	m.data[g.ID] = g
	return nil
}

// IntegrationDataStore wraps the mock to provide scanner-specific functionality
type IntegrationDataStore struct {
	mediaFileRepo model.MediaFileRepository
	albumRepo     model.AlbumRepository
	artistRepo    model.ArtistRepository
	genreRepo     model.GenreRepository
	libraryRepo   model.LibraryRepository
}

func NewIntegrationDataStore() *IntegrationDataStore {
	return &IntegrationDataStore{
		mediaFileRepo: &IntegrationMediaFileRepo{
			MockMediaFileRepo: tests.CreateMockMediaFileRepo(),
		},
		albumRepo: &IntegrationAlbumRepo{
			MockAlbumRepo: tests.CreateMockAlbumRepo(),
		},
		artistRepo: &IntegrationArtistRepo{
			MockArtistRepo: tests.CreateMockArtistRepo(),
		},
		genreRepo: &IntegrationGenreRepo{
			data: make(map[string]*model.Genre),
		},
	}
}

func (ds *IntegrationDataStore) Library(ctx context.Context) model.LibraryRepository {
	if ds.libraryRepo == nil {
		ds.libraryRepo = &MockLibraryRepo{}
	}
	return ds.libraryRepo
}

func (ds *IntegrationDataStore) Album(ctx context.Context) model.AlbumRepository {
	return ds.albumRepo
}

func (ds *IntegrationDataStore) Artist(ctx context.Context) model.ArtistRepository {
	return ds.artistRepo
}

func (ds *IntegrationDataStore) MediaFile(ctx context.Context) model.MediaFileRepository {
	return ds.mediaFileRepo
}

func (ds *IntegrationDataStore) Genre(ctx context.Context) model.GenreRepository {
