}

func (ds *IntegrationDataStore) PlayQueue(ctx context.Context) model.PlayQueueRepository {
	return struct{ model.PlayQueueRepository }{}
}

func (ds *IntegrationDataStore) Transcoding(ctx context.Context) model.TranscodingRepository {
