}

func (ds *IntegrationDataStore) Share(ctx context.Context) model.ShareRepository {
	return struct{ model.ShareRepository }{}
}

func (ds *IntegrationDataStore) Property(ctx context.Context) model.PropertyRepository {
	return struct{ model.PropertyRepository }{}
}

func (ds *IntegrationDataStore) User(ctx context.Context) model.UserRepository {
	return tests.CreateMockUserRepo()
}

func (ds *IntegrationDataStore) UserProps(ctx context.Context) model.UserPropsRepository {
	return &tests.MockedUserPropsRepo{}
}

func (ds *IntegrationDataStore) ScrobbleBuffer(ctx context.Context) model.ScrobbleBufferRepository {
	return struct{ model.ScrobbleBufferRepository }{}
}

func (ds *IntegrationDataStore) WithTx(block func(tx model.DataStore) error) error {
