}

func (ds *IntegrationDataStore) GC(ctx context.Context, rootFolder string) error {
	return nil
}

func (ds *IntegrationDataStore) Resource(ctx context.Context, model interface{}) model.ResourceRepository {
	return struct{ model.ResourceRepository }{}
}

// MockLibraryRepo implements LibraryRepository for testing
type MockLibraryRepo struct {
	libraries map[int]*model.Library
}

func (m *MockLibraryRepo) Get(id int) (*model.Library, error) {
	return m.libraries[id], nil
}

func (m *MockLibraryRepo) Put(lib *model.Library) error {
	if m.libraries == nil {
		m.libraries = make(map[int]*model.Library)
	}
	m.libraries[lib.ID] = lib
	return nil
}

func (m *MockLibraryRepo) StoreMusicFolder() error {
	return nil
}

func (m *MockLibraryRepo) AddArtist(id int, artistID string) error {
	return nil
}

func (m *MockLibraryRepo) UpdateLastScan(id int, t time.Time) error {
	if m.libraries[id] != nil {
		m.libraries[id].LastScanAt = t
	}
	return nil
}

func (m *MockLibraryRepo) GetAll(...model.QueryOptions) (model.Libraries, error) {
	var libs model.Libraries
	for _, lib := range m.libraries {
		libs = append(libs, *lib)
	}
	return libs, nil
}

// Helper functions

// copyTestFile copies a file from fixtures to the destination path
func copyTestFile(srcFixture, destPath string) error {
	src, err := os.Open(srcFixture)
	if err != nil {
		return err
	}
	defer src.Close()

	dst, err := os.Create(destPath)
	if err != nil {
		return err
	}
	defer dst.Close()

	_, err = io.Copy(dst, src)
	return err
}

// setupTestLibrary creates a temporary library directory and copies test audio files
func setupTestLibrary(t *testing.T) (string, *model.Library, func()) {
	tmpDir := t.TempDir()

	// Create subdirectory for better testing
	musicDir := filepath.Join(tmpDir, "music")
	if err := os.MkdirAll(musicDir, 0o755); err != nil {
		t.Fatalf("Failed to create music directory: %v", err)
	}

	// Copy test audio files from fixtures
	fixturesDir := "tests/fixtures"
	sourceFile := filepath.Join(fixturesDir, "test.mp3")

	// Copy a test file to the music directory with a recognizable name
	destFile := filepath.Join(musicDir, "test.mp3")
	if err := copyTestFile(sourceFile, destFile); err != nil {
		t.Logf("Note: Could not copy test fixture (this is expected if fixtures aren't available): %v", err)
		// Create a minimal empty file for testing structure only
		if err := os.WriteFile(destFile, []byte{}, 0o644); err != nil {
			t.Fatalf("Failed to create test file: %v", err)
		}
	}

	// Create a library record
	lib := &model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       musicDir,
		LastScanAt: time.Now().Add(-1 * time.Hour), // Simulate previous scan
		CreatedAt:  time.Now(),
		UpdatedAt:  time.Now(),
	}

	// Return cleanup function
	cleanup := func() {
		_ = os.RemoveAll(tmpDir)
	}

	return musicDir, lib, cleanup
}

// Tests

// TestScannerBasicScan tests that the scanner can scan a directory and create media files
func TestScannerBasicScan(t *testing.T) {
	tests.Init(t, true)
	ctx := context.Background()

	musicDir, lib, cleanup := setupTestLibrary(t)
	defer cleanup()

	ds := NewIntegrationDataStore()
	ds.libraryRepo.(*MockLibraryRepo).libraries = map[int]*model.Library{
		lib.ID: lib,
	}

	// Create scanner
	scanner := NewTagScanner(ds, &MockPlaylists{}, &MockCacheWarmer{})

	// Perform scan
	progress := make(chan uint32, 100)
	count, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	// Verify
	if count < 0 {
		t.Errorf("Expected non-negative count, got %d", count)
	}

	// Check that media files were added to the store
	mfs, _ := ds.MediaFile(ctx).GetAll()
	if len(mfs) == 0 {
		t.Logf("No files scanned (expected if test fixtures not available)")
		return
	}

	// Verify basic structure of media file
	if len(mfs) > 0 {
		mf := mfs[0]
		if mf.Path == "" {
			t.Error("MediaFile path should not be empty")
		}
	}
}

// TestScannerMetadataExtraction tests that metadata is correctly extracted from audio files
func TestScannerMetadataExtraction(t *testing.T) {
	tests.Init(t, true)
	ctx := context.Background()

	musicDir, lib, cleanup := setupTestLibrary(t)
	defer cleanup()

	ds := NewIntegrationDataStore()
	ds.libraryRepo.(*MockLibraryRepo).libraries = map[int]*model.Library{
		lib.ID: lib,
	}

	scanner := NewTagScanner(ds, &MockPlaylists{}, &MockCacheWarmer{})

	// Perform scan
	progress := make(chan uint32, 100)
	count, err := scanner.Scan(ctx, *lib, true, progress)
	close(progress)

	if err != nil && count == 0 {
		t.Logf("Scan returned no results (expected if fixtures not available)")
		return
	}

	// Get scanned files
	mfs, _ := ds.MediaFile(ctx).GetAll()
	if len(mfs) == 0 {
		t.Logf("No files scanned")
		return
	}

	// Verify metadata fields are populated
	mf := mfs[0]

	// Essential fields should be set
	if mf.Path == "" {
		t.Error("MediaFile path should be populated")
	}

	// Title should either be from metadata or derived from filename
	if mf.Title == "" {
		t.Error("MediaFile title should be populated")
	}

	// Verify timestamps are set
	if mf.CreatedAt.IsZero() {
		t.Error("CreatedAt should be set")
	}

	if mf.UpdatedAt.IsZero() {
		t.Error("UpdatedAt should be set")
	}
}

// TestScannerIncrementalScan tests that re-scanning with no changes detects no changes
func TestScannerIncrementalScan(t *testing.T) {
	tests.Init(t, true)
	ctx := context.Background()

	musicDir, lib, cleanup := setupTestLibrary(t)
	defer cleanup()

	ds := NewIntegrationDataStore()
	ds.libraryRepo.(*MockLibraryRepo).libraries = map[int]*model.Library{
		lib.ID: lib,
	}

	scanner := NewTagScanner(ds, &MockPlaylists{}, &MockCacheWarmer{})

	// First scan - full scan
	progress1 := make(chan uint32, 100)
	count1, _ := scanner.Scan(ctx, *lib, true, progress1)
	close(progress1)

	// Get the initial file count
	initialFiles, _ := ds.MediaFile(ctx).GetAll()
	initialCount := len(initialFiles)

	if initialCount == 0 {
		t.Logf("First scan returned no files (expected if fixtures not available)")
