	// Get initial files
	initialFiles, _ := ds.MediaFile(ctx).GetAll()
	if len(initialFiles) == 0 {
		t.Logf("No files scanned in first pass")
		return
	}

	// Delete first file from filesystem
	fileToDelete := initialFiles[0].Path
	if err := os.Remove(fileToDelete); err != nil {
		t.Fatalf("Failed to delete test file: %v", err)
	}

	// Update last scan time
	lib.LastScanAt = time.Now().Add(-1 * time.Hour)

	// Second scan - should detect deletion
	progress2 := make(chan uint32, 100)
	scanner.Scan(ctx, *lib, false, progress2)
	close(progress2)

	// Verify file was removed or marked appropriately
	// The scan should have processed the deleted file
	t.Logf("Deletion detection test completed")
}

