// copyTestFile copies a file from fixtures to the destination path
func copyTestFile(srcFixture, destPath string) error {
	src, err := os.Open(srcFixture)
	if err != nil {
		return err
	}
	defer src.Close()

	dst, err := os.Create(destPath)
	if err != nil {
		return err
	}
	defer dst.Close()

	_, err = io.Copy(dst, src)
	return err
}

// setupTestLibrary creates a temporary library directory and copies test audio files
func setupTestLibrary(t *testing.T) (string, *model.Library, func()) {
	tmpDir := t.TempDir()

	// Create subdirectory for better testing
	musicDir := filepath.Join(tmpDir, "music")
	if err := os.MkdirAll(musicDir, 0o755); err != nil {
		t.Fatalf("Failed to create music directory: %v", err)
	}

	// Copy test audio files from fixtures
	fixturesDir := "tests/fixtures"
	sourceFile := filepath.Join(fixturesDir, "test.mp3")

	// Copy a test file to the music directory with a recognizable name
	destFile := filepath.Join(musicDir, "test.mp3")
	if err := copyTestFile(sourceFile, destFile); err != nil {
		t.Logf("Note: Could not copy test fixture (this is expected if fixtures aren't available): %v", err)
		// Create a minimal empty file for testing structure only
		if err := os.WriteFile(destFile, []byte{}, 0o644); err != nil {
			t.Fatalf("Failed to create test file: %v", err)
		}
	}

	// Create a library record
	lib := &model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       musicDir,
		LastScanAt: time.Now().Add(-1 * time.Hour), // Simulate previous scan
		CreatedAt:  time.Now(),
		UpdatedAt:  time.Now(),
	}

	// Return cleanup function
	cleanup := func() {
		_ = os.RemoveAll(tmpDir)
	}

	return musicDir, lib, cleanup
}

